function candidate(value, encoder, charset) {
  if (value.length === 0) {
    return value;
  }

  var text = typeof value === "symbol" ? value.toString() : String(value);

  if (charset === "ISO-8859-1") {
    return escape(text).replace(/%u([0-9a-fA-F]{4})/g, function(match, hex) {
      return "%26%23" + parseInt(hex, 16) + "%3B";
    });
  }

  var result = "";
  for (var i = 0; i < text.length; i++) {
    var code = text.charCodeAt(i);

    if (
      (code >= 48 && code <= 57) ||
      (code >= 65 && code <= 90) ||
      (code >= 97 && code <= 122) ||
      code === 45 ||
      code === 46 ||
      code === 95 ||
      code === 126
    ) {
      result += text.charAt(i);
    } else if (code < 128) {
      result += "%" + code.toString(16).toUpperCase().padStart(2, "0");
    } else if (code < 2048) {
      result += "%" + (192 | (code >> 6)).toString(16).toUpperCase();
      result += "%" + (128 | (code & 63)).toString(16).toUpperCase();
    } else if (code < 55296 || code > 57343) {
      result += "%" + (224 | (code >> 12)).toString(16).toUpperCase();
      result += "%" + (128 | ((code >> 6) & 63)).toString(16).toUpperCase();
      result += "%" + (128 | (code & 63)).toString(16).toUpperCase();
    } else {
      i++;
      var next = text.charCodeAt(i);
      var point = 65536 + (((code & 1023) << 10) | (next & 1023));
      result += "%" + (240 | (point >> 18)).toString(16).toUpperCase();
      result += "%" + (128 | ((point >> 12) & 63)).toString(16).toUpperCase();
      result += "%" + (128 | ((point >> 6) & 63)).toString(16).toUpperCase();
      result += "%" + (128 | (point & 63)).toString(16).toUpperCase();
    }
  }

  return result;
}
